body::before {
  content: '';
  position: fixed;
  inset: 0;
  pointer-events: none;
  z-index: 0;
  background-image:
    linear-gradient(rgba(255, 255, 255, 0.024) 1px, transparent 1px),
    linear-gradient(90deg, rgba(255, 255, 255, 0.024) 1px, transparent 1px);
  background-size: 48px 48px;
}

/* REMOVE the old body::after orb completely — no second pseudo-element */
body::after {
  display: none;
}

/* ── Selection ── */
::selection {
  background: rgba(99, 235, 255, 0.25);
  color: #fff;
}

/* ── Scrollbar ── */
::-webkit-scrollbar {
  width: 5px;
  height: 5px;
}
::-webkit-scrollbar-track {
  background: transparent;
}
::-webkit-scrollbar-thumb {
  background: rgba(99, 235, 255, 0.10);
  border-radius: 999px;
}
