.stagger-item:nth-child(19) { animation-delay: 900ms; }
.stagger-item:nth-child(20) { animation-delay: 950ms; }

/* ── Page Transition Overlay (used by transitions.js) ── */
#apex-transition-overlay {
  position: fixed;
  inset: 0;
  z-index: 9999;
  background: var(--bg);
  display: flex;
  flex-direction: column;
