Before calling Bedrock, gather session context:
```javascript
function gatherSessionContext(room) {
  const ctx = []

  // Party info
  if (room.players?.length) {
    ctx.push('## Current Party')
    for (const p of room.players) {
      const char = p.character || {}
      ctx.push(`- **${p.name}** (${char.race || '?'} ${char.class || '?'} Lv${char.level || 1}) HP: ${char.hp || '?'}/${char.maxHp || '?'} AC: ${char.ac || '?'}`)
    }
  }

  // Initiative order (if combat active)
  if (room.initiative?.length) {
    ctx.push('\n## Initiative Order')
    room.initiative.forEach((entry, i) => {
      ctx.push(`${i + 1}. ${entry.name} (${entry.initiative})${entry.current ? ' ← CURRENT TURN' : ''}`)
    })
  }

  // Recent dice rolls (last 10)
  if (room.rolls?.length) {
    ctx.push('\n## Recent Dice Rolls')
    room.rolls.slice(-10).forEach(r => {
      ctx.push(`- ${r.player}: ${r.notation} = **${r.total}** ${r.details || ''}`)
    })
  }

  // Session notes
  if (room.notes) {
    ctx.push('\n## Session Notes')
    ctx.push(room.notes)
  }

  return ctx.join('\n')
}
```

