app.post('/api/deep-think', async (req) => {
  if (!requireAdmin(req)) return { ok: false, error: 'Admin required' }
  const { topic, agents } = req.body || {}
  if (!topic) return { ok: false, error: 'Topic required' }

  // Default 3 agents: Rafael (strategy), Uriel (technical), Samael (challenge)
  const debateAgents = agents || ['rafael', 'uriel', 'samael']

  // Phase 1: Each agent gives initial take (parallel)
  const initialResponses = await Promise.all(debateAgents.map(async (agentId) => {
    const soul = AGENT_SOULS[agentId] || ''
    const prompt = `${soul}\n\nYou are in a DEEP THINK debate session. Topic: "${topic}"\n\nGive your initial analysis and position. Be specific, opinionated, and constructive. Consider risks, opportunities, and practical implementation. 300-500 words.`
    const response = await callBedrock(prompt) // use existing Bedrock call pattern
    return { agentId, phase: 'initial', response }
  }))

  // Phase 2: Each agent responds to others' takes (sequential for context)
  const debateResponses = await Promise.all(debateAgents.map(async (agentId) => {
    const soul = AGENT_SOULS[agentId] || ''
    const othersViews = initialResponses.filter(r => r.agentId !== agentId)
      .map(r => `**${r.agentId}** said: ${r.response}`).join('\n\n')
    const prompt = `${soul}\n\nDEEP THINK debate continues. Topic: "${topic}"\n\nOther agents said:\n${othersViews}\n\nRespond to their points. Where do you agree? Where do you push back? What did they miss? Be direct. 200-400 words.`
    const response = await callBedrock(prompt)
    return { agentId, phase: 'debate', response }
  }))

  // Phase 3: Synthesis (use Rafael or a neutral agent)
  const allContent = [...initialResponses, ...debateResponses]
    .map(r => `**${r.agentId}** (${r.phase}): ${r.response}`).join('\n\n---\n\n')
  const synthesisPrompt = `You are synthesizing a DEEP THINK debate session.\n\nTopic: "${topic}"\n\nAll agent contributions:\n${allContent}\n\nProduce a final synthesis:\n1. **Consensus Points** — what everyone agrees on\n2. **Key Debates** — where agents disagreed and the best resolution\n3. **Recommended Plan** — concrete action items with priorities\n4. **Risks & Mitigations** — top 3 risks identified\n5. **Open Questions** — what still needs to be decided\n\nBe specific and actionable. This will be turned into a visual plan.`
  const synthesis = await callBedrock(synthesisPrompt)

  // Save result
  const result = {
    id: 'dt-' + Date.now(),
    topic,
    agents: debateAgents,
    phases: { initial: initialResponses, debate: debateResponses },
    synthesis,
    createdAt: Date.now()
  }

  // Store in data/deep-thinks.json
