  let data = { items: [] }
  try { data = JSON.parse(readFileSync(file, 'utf8')) } catch {}
  data.items.unshift(result)
  if (data.items.length > 20) data.items = data.items.slice(0, 20)
  writeFileSync(file, JSON.stringify(data, null, 2))

  return { ok: true, result }
})

