## 1. Rate Limiting
Add per-user rate limiting for API calls:

- Free users (role: 'user'): 50 messages/day, 3 deep thinks/day
- Admin users (role: 'admin'): unlimited

Implementation: in-memory Map tracking calls per user per day. Reset at midnight UTC.

Add this BEFORE the existing route handlers:

```javascript
// Rate limiting
const rateLimits = new Map(); // userId -> {messages: count, deepThinks: count, date: 'YYYY-MM-DD'}

function checkRateLimit(username, type = 'message') {
  const today = new Date().toISOString().split('T')[0];
  const auth = loadAuth();
  const user = auth.users[username];
  if (!user) return { allowed: false, reason: 'Unknown user' };
  if (user.role === 'admin') return { allowed: true };

  let limits = rateLimits.get(username);
  if (!limits || limits.date !== today) {
    limits = { messages: 0, deepThinks: 0, date: today };
    rateLimits.set(username, limits);
  }

  if (type === 'message' && limits.messages >= 50) {
    return { allowed: false, reason: 'Daily message limit (50) reached' };
  }
  if (type === 'deepThink' && limits.deepThinks >= 3) {
    return { allowed: false, reason: 'Daily Deep Think limit (3) reached' };
  }

  limits[type === 'deepThink' ? 'deepThinks' : 'messages']++;
  return { allowed: true, remaining: type === 'deepThink' ? 3 - limits.deepThinks : 50 - limits.messages };
}
```

Apply to:
- POST /api/chat → checkRateLimit(username, 'message')
- POST /api/deep-think → checkRateLimit(username, 'deepThink')

## 2. Cost Tracking
Track Bedrock token usage per user.

Add to the existing streamAI or callBedrockSimple function:

```javascript
// Cost tracking
const COST_FILE = join(__dirname, 'data', 'costs.json');

function trackCost(username, inputTokens, outputTokens, model) {
  let costs = {};
  try { costs = JSON.parse(readFileSync(COST_FILE, 'utf8')); } catch {}

  const today = new Date().toISOString().split('T')[0];
  if (!costs[today]) costs[today] = {};
  if (!costs[today][username]) costs[today][username] = { input: 0, output: 0, calls: 0 };

  costs[today][username].input += inputTokens;
  costs[today][username].output += outputTokens;
  costs[today][username].calls += 1;

  // Keep only last 30 days
  const keys = Object.keys(costs).sort();
  while (keys.length > 30) { delete costs[keys.shift()]; }

  writeFileSync(COST_FILE, JSON.stringify(costs, null, 2));
}
```

